// M63: classifyInputSchemaFirstPropertyMaxLength(inputSchema) → 'length_capped'|'length_uncapped'|'not_applicable'|'unknown'
// Classification rules (frozen — any change is a governance event):
//   inputSchema missing/null/undefined → 'unknown' (reason: input_schema_field_missing)
//   inputSchema not plain non-null object/is array → 'unknown' (reason: input_schema_field_not_object)
//   inputSchema.type missing or non-string → 'unknown' (reason: input_schema_type_missing_or_invalid)
//   inputSchema.type is a string but not 'object' → 'not_applicable' (no warning; non-object input has no first property)
//   inputSchema.type === 'object', properties missing/null/not-plain-object → 'unknown' (reason: input_schema_properties_field_missing_when_type_is_object)
//   inputSchema.type === 'object', properties is plain object, Object.keys(properties).length === 0 → 'not_applicable' (no warning)
//   Otherwise: firstKey = Object.keys(properties)[0]; firstVal = properties[firstKey];
//              if firstVal is not a plain non-null object → 'unknown' (reason: input_schema_properties_first_property_descriptor_invalid — FIFTH FROZEN CODE)
//              HAS-OWN-PROPERTY check: Object.prototype.hasOwnProperty.call(firstVal, 'maxLength')
//              if NOT hasOwn OR firstVal.maxLength === undefined OR firstVal.maxLength === null → 'length_uncapped' (null-as-absent, no warning)
//              if Number.isInteger(firstVal.maxLength) && firstVal.maxLength >= 0 → 'length_capped'
//                (EXPLICIT-ZERO-IS-CAPPED: maxLength === 0 → length_capped, mirrors M58/M60/M61/M62 explicit-default-value precedent — no warning)
//              if firstVal.maxLength is present, non-null, not a non-negative integer → 'unknown'
//                (reason: input_schema_properties_first_property_max_length_invalid_when_present — SIXTH FROZEN CODE)
//                Covers: negative integer (-1), fractional (1.5), NaN, Infinity, -Infinity, string, boolean, array, plain object
// STRICT numeric check: Number.isInteger() && >= 0. NO Number()/parseInt()/truthy coercion.
// Object.keys insertion-order semantics preserved. MUST NOT sort or re-order property keys.
// Per-property maxLength beyond the FIRST is NOT walked (reserved for M-Ceiling-All-Properties).
// Nested-object property maxLength annotation NOT walked (reserved for M-Ceiling-Nested).
// output_schema first-property maxLength is NOT classified (reserved for M-Ceiling-Output).
// input_schema_first_property_max_length MUST NOT be written into tusq.manifest.json (non-persistence rule).
function classifyInputSchemaFirstPropertyMaxLength(inputSchema) {
  if (inputSchema === null || inputSchema === undefined) {
    return 'unknown';
  }
  if (typeof inputSchema !== 'object' || Array.isArray(inputSchema)) {
    return 'unknown';
  }
  const schemaType = inputSchema.type;
  if (typeof schemaType !== 'string') {
    return 'unknown';
  }
  if (schemaType !== 'object') {
    return 'not_applicable';
  }
  // inputSchema.type === 'object'
  const properties = inputSchema.properties;
  if (properties === null || properties === undefined || typeof properties !== 'object' || Array.isArray(properties)) {
    return 'unknown';
  }
  const keys = Object.keys(properties);
  if (keys.length === 0) {
    return 'not_applicable';
  }
  const firstKey = keys[0];
  const firstVal = properties[firstKey];
  if (firstVal === null || firstVal === undefined || typeof firstVal !== 'object' || Array.isArray(firstVal)) {
    return 'unknown';
  }
  // maxLength absent, undefined, or null → length_uncapped (null-as-absent, mirroring M55/M56/M57/M58/M59/M60/M61/M62)
  if (!Object.prototype.hasOwnProperty.call(firstVal, 'maxLength') || firstVal.maxLength === undefined || firstVal.maxLength === null) {
    return 'length_uncapped';
  }
  // EXPLICIT-ZERO-IS-CAPPED and positive integers: Number.isInteger && >= 0 → length_capped (no warning)
  if (Number.isInteger(firstVal.maxLength) && firstVal.maxLength >= 0) {
    return 'length_capped';
  }
  // present, non-null, not a non-negative integer → unknown (6th frozen code)
  return 'unknown';
}

// M63: buildInputSchemaFirstPropertyMaxLengthIndex(manifest, manifestPath) → index object
// Builds a full unfiltered input schema first property maxLength annotation index from the manifest's capabilities[].
// Bucket iteration order: length_capped → length_uncapped → not_applicable (closed-enum order), then unknown last.
// Empty buckets MUST NOT appear.
// input_schema_first_property_max_length MUST NOT be written into tusq.manifest.json (non-persistence rule).
function buildInputSchemaFirstPropertyMaxLengthIndex(manifest, manifestPath) {
  const manifestVersion = typeof manifest.manifest_version === 'number' ? manifest.manifest_version : null;
  const generatedAt = typeof manifest.generated_at === 'string' ? manifest.generated_at : null;
  const capabilities = manifest.capabilities;
  const warnings = [];

  if (capabilities.length === 0) {
    return {
      manifest_path: manifestPath,
      manifest_version: manifestVersion,
      generated_at: generatedAt,
      first_property_max_length_states: [],
      warnings
    };
  }

  // Named (non-unknown) bucket values — the three ordered bucket keys (excludes unknown).
  const namedBuckets = new Set(INPUT_SCHEMA_FIRST_PROPERTY_MAX_LENGTH_BUCKET_ORDER);

  // Collect capabilities into buckets keyed by their input_schema_first_property_max_length.
  const buckets = Object.create(null); // bucketKey → capability[]
  let hasUnknownBucket = false;

  for (const capability of capabilities) {
    const inputSchema = Object.prototype.hasOwnProperty.call(capability, 'input_schema')
      ? capability.input_schema
      : undefined;

    // Determine warning reason if input_schema or first-property descriptor is malformed.
    // Six frozen warning reason codes (M63 PM DEC-003):
    //   1. input_schema_field_missing
    //   2. input_schema_field_not_object
    //   3. input_schema_type_missing_or_invalid
    //   4. input_schema_properties_field_missing_when_type_is_object
    //   5. input_schema_properties_first_property_descriptor_invalid (fifth code, carried forward from M55/M56/M57/M58/M59/M60/M61/M62)
    //   6. input_schema_properties_first_property_max_length_invalid_when_present (NEW axis-specific code for M63)
    let warningReason = null;
    if (inputSchema === undefined || inputSchema === null) {
      warningReason = 'input_schema_field_missing';
    } else if (typeof inputSchema !== 'object' || Array.isArray(inputSchema)) {
      warningReason = 'input_schema_field_not_object';
    } else if (typeof inputSchema.type !== 'string') {
      warningReason = 'input_schema_type_missing_or_invalid';
    } else if (inputSchema.type === 'object') {
      const props = inputSchema.properties;
      if (props === null || props === undefined || typeof props !== 'object' || Array.isArray(props)) {
        warningReason = 'input_schema_properties_field_missing_when_type_is_object';
      } else {
        const keys = Object.keys(props);
        if (keys.length > 0) {
          const firstKey = keys[0];
          const firstVal = props[firstKey];
          if (firstVal === null || firstVal === undefined || typeof firstVal !== 'object' || Array.isArray(firstVal)) {
            warningReason = 'input_schema_properties_first_property_descriptor_invalid';
          } else if (Object.prototype.hasOwnProperty.call(firstVal, 'maxLength') && firstVal.maxLength !== undefined && firstVal.maxLength !== null) {
            // maxLength present non-null: must be a non-negative integer; otherwise emit 6th warning
            if (!(Number.isInteger(firstVal.maxLength) && firstVal.maxLength >= 0)) {
              warningReason = 'input_schema_properties_first_property_max_length_invalid_when_present';
            }
            // else: valid non-negative integer — no warning (→ length_capped)
          }
          // else: maxLength absent, undefined, or null → length_uncapped, no warning
        }
        // keys.length === 0 → not_applicable, no warning
      }
    }
    // Note: input_schema.type is a string but not 'object' → not_applicable, no warning

    if (warningReason !== null) {
      warnings.push({ capability: capability.name, reason: warningReason });
    }

    const maxLengthClass = classifyInputSchemaFirstPropertyMaxLength(inputSchema);
    const isNamedBucket = namedBuckets.has(maxLengthClass);
    const bucketKey = isNamedBucket ? maxLengthClass : '__unknown__';

    if (!isNamedBucket) {
      if (!hasUnknownBucket) {
        hasUnknownBucket = true;
        buckets['__unknown__'] = [];
      }
      buckets['__unknown__'].push(capability);
    } else {
      if (!buckets[bucketKey]) {
        buckets[bucketKey] = [];
      }
      buckets[bucketKey].push(capability);
    }
  }

  // Iterate in closed-enum order: length_capped → length_uncapped → not_applicable, then unknown last.
  // Empty buckets MUST NOT appear.
  const orderedBucketKeys = [
    ...INPUT_SCHEMA_FIRST_PROPERTY_MAX_LENGTH_BUCKET_ORDER.filter((k) => buckets[k]),
    ...(hasUnknownBucket ? ['__unknown__'] : [])
  ];

  const firstPropertyMaxLengthStates = orderedBucketKeys.map((bucketKey) => {
    const isUnknownBucket = bucketKey === '__unknown__';
    const isNotApplicableBucket = bucketKey === 'not_applicable';
    const maxLengthKey = isUnknownBucket
      ? _guardInputSchemaFirstPropertyMaxLengthBucketKey('unknown')
      : _guardInputSchemaFirstPropertyMaxLengthBucketKey(bucketKey);
    const aggregationKey = isUnknownBucket
      ? _guardInputSchemaFirstPropertyMaxLengthAggregationKey('unknown')
      : isNotApplicableBucket
        ? _guardInputSchemaFirstPropertyMaxLengthAggregationKey('not_applicable')
        : _guardInputSchemaFirstPropertyMaxLengthAggregationKey('string_length_ceiling_constraint');
    const caps = buckets[bucketKey];
    const capabilityNames = caps.map((c) => c.name);
    const approvedCount = caps.filter((c) => c.approved === true).length;
    const gatedCount = caps.length - approvedCount;
    const hasDestructiveSideEffect = caps.some((c) => c.side_effect_class === 'destructive');
    const hasRestrictedOrConfidentialSensitivity = caps.some(
      (c) => c.sensitivity_class === 'restricted' || c.sensitivity_class === 'confidential'
    );

    return {
      input_schema_first_property_max_length: maxLengthKey,
      aggregation_key: aggregationKey,
      capability_count: caps.length,
      capabilities: capabilityNames,
      approved_count: approvedCount,
      gated_count: gatedCount,
      has_destructive_side_effect: hasDestructiveSideEffect,
      has_restricted_or_confidential_sensitivity: hasRestrictedOrConfidentialSensitivity
    };
  });

  return {
    manifest_path: manifestPath,
    manifest_version: manifestVersion,
    generated_at: generatedAt,
    first_property_max_length_states: firstPropertyMaxLengthStates,
    warnings
  };
}

